# Refactored Code

```python
def _load_file(path, file_type):
    """Load data from CSV or JSON file."""
    with open(path) as f:
        if file_type == 'csv':
            return csv.DictReader(f)
        elif file_type == 'json':
            return json.load(f)

def _process_row(row):
    """Normalize and validate a single row."""
    name = row['name'].strip().title()
    email = row['email'].strip().lower()
    age = int(row['age'])

    if age >= 18 and '@' in email:
        return {'name': name, 'email': email, 'age': age}
    return None

def _process_data(data):
    """Process a collection of rows."""
    return [result for result in (
        _process_row(row) for row in data
    ) if result is not None]

def process_csv(path):
    data = _load_file(path, 'csv')
    return _process_data(data)

def process_json(path):
    data = _load_file(path, 'json')
    return _process_data(data)
```

## Key Improvements

1. **`_process_row()`** - Extracted common row processing logic
2. **`_process_data()`** - Extracted common filtering/collection logic
3. **`_load_file()`** - Extracted file loading logic
4. **Cleaner public API** - `process_csv()` and `process_json()` are now thin wrappers

## Alternative: More Generic Approach

If you want even more flexibility:

```python
def process_file(path, loader):
    """Generic file processor."""
    with open(path) as f:
        data = loader(f)

    return [result for result in (
        _process_row(row) for row in data
    ) if result is not None]

def process_csv(path):
    return process_file(path, csv.DictReader)

def process_json(path):
    return process_file(path, json.load)
```

This eliminates the `_load_file()` function entirely by passing loaders as arguments.

